import React from "react";
import * as structuredDataReact from "@mdwrk/lander-react-structured-data";
import { SemanticShell, SemanticStructuredDataGate, joinClassNames, renderJsonPreview } from "./shared.js";

export interface GeneratedPropertyViewModel {
  eyebrow?: React.ReactNode;
  footer?: React.ReactNode;
  subtitle?: React.ReactNode;
}

export interface GeneratedPropertyProps<T = Record<string, unknown>> {
  value: T;
  description?: string;
  examples?: T[];
  body?: React.ReactNode;
  className?: string;
  emitStructuredData?: boolean;
  structuredDataOverrides?: T;
  viewModel?: GeneratedPropertyViewModel;
}

export interface PropertyAboutProps extends GeneratedPropertyProps<Record<string, unknown>> {}
export function PropertyAbout({
  value,
  description = "The subject matter of an object.",
  examples,
  body,
  className,
  emitStructuredData = true,
  structuredDataOverrides,
  viewModel,
}: PropertyAboutProps) {
  return (
    <>
      <SemanticStructuredDataGate emitStructuredData={emitStructuredData}>
        <structuredDataReact.AboutPropertyStructuredData data={(structuredDataOverrides ?? value) as never} />
      </SemanticStructuredDataGate>
      <SemanticShell
        kind="schema-property-about"
        title="about"
        eyebrow={viewModel?.eyebrow ?? "Property"}
        subtitle={viewModel?.subtitle}
        description={description}
        className={joinClassNames("lander-semantic--schema-property-about", className)}
        meta={[
          { label: "Value", value: renderJsonPreview(value) },
          ...(examples?.length ? [{ label: "Examples", value: renderJsonPreview(examples) }] : []),
        ]}
        body={body}
        footer={viewModel?.footer}
      />
    </>
  );
}

